(function () {
    try {
        var content = execution.getVariables();
        var requestId = content.get('id');
        var currentLevel = parseInt(content.get('currentLevel'), 10);
        logger.error('aaronPOC-Loop: actors expression started, currentLevel=' + currentLevel);

        var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
        var emails = requestObj.request.custom.approverEmails;
        var emailList = emails.split(',');
        var approverEmail = emailList[currentLevel].trim();

        logger.error('aaronPOC-Loop: level=' + currentLevel + ', looking up approver: ' + approverEmail);

        var result = [];
        var queryResult = openidm.query('managed/alpha_user', {
            '_queryFilter': '/mail eq "' + approverEmail + '"'
        });
        if (queryResult && queryResult.result && queryResult.result.length > 0) {
            var user = queryResult.result[0];
            result.push({
                'id': 'managed/user/' + user._id,
                'permissions': {
                    'approve': true,
                    'reject': true,
                    'reassign': true,
                    'modify': false,
                    'comment': true
                }
            });
            logger.error('aaronPOC-Loop: found approver: ' + user._id);
        } else {
            logger.error('aaronPOC-Loop: no user found for email: ' + approverEmail);
        }
        return result;
    } catch (e) {
        logger.error('aaronPOC-Loop: actors expression FAILED: ' + e);
        return [];
    }
})()
